import { db } from "@/db/db";
import { credentials } from "@/db/schema";
import { eq, and } from "drizzle-orm";
import { decryptObject } from "@/lib/encryption";
import { Client as PgClient } from "pg";
import mysql from "mysql2/promise";
import { MongoClient } from "mongodb";
import { createClient as createRedisClient } from "redis";
import OpenAI from "openai";
import Anthropic from "@anthropic-ai/sdk";
import { createLogger } from "@/lib/logger";

const log = createLogger('CredentialService');

// Type definitions for different credential configs
export interface PostgresConfig {
  host: string;
  port: number;
  database: string;
  user: string;
  password: string;
  ssl?: boolean;
}

export interface MySQLConfig {
  host: string;
  port: number;
  database: string;
  user: string;
  password: string;
  ssl?: boolean;
}

export interface MongoDBConfig {
  connectionString: string;
  database: string;
}

export interface RedisConfig {
  host: string;
  port: number;
  password?: string;
  database?: number;
}

export interface OpenAIConfig {
  apiKey: string;
  organization?: string;
  baseUrl?: string;
}

export interface AnthropicConfig {
  apiKey: string;
  baseUrl?: string;
}

export interface GoogleAIConfig {
  apiKey: string;
  baseUrl?: string;
}

export interface OllamaConfig {
  baseUrl: string;
}

export type CredentialConfig = PostgresConfig | MySQLConfig | MongoDBConfig | RedisConfig | OpenAIConfig | AnthropicConfig | GoogleAIConfig | OllamaConfig;

// Client wrapper classes
export class PostgresCredential {
  private client: PgClient | null = null;
  private config: PostgresConfig;

  constructor(config: PostgresConfig) {
    this.config = config;
  }

  private createClient(): PgClient {
    return new PgClient({
      host: this.config.host,
      port: this.config.port,
      database: this.config.database,
      user: this.config.user,
      password: this.config.password,
      ssl: this.config.ssl ? { rejectUnauthorized: false } : false,
    });
  }

  async connect() {
    if (!this.client) {
      this.client = this.createClient();
      await this.client.connect();
    }
  }

  async query(sql: string, params?: unknown[]) {
    await this.connect();
    return this.client!.query(sql, params);
  }

  async disconnect() {
    if (this.client) {
      await this.client.end();
      this.client = null;  // Allow creating a new client on next connect
    }
  }
}

export class MySQLCredential {
  private connection: mysql.Connection | null = null;

  constructor(private config: MySQLConfig) {}

  async connect() {
    if (!this.connection) {
      this.connection = await mysql.createConnection({
        host: this.config.host,
        port: this.config.port,
        database: this.config.database,
        user: this.config.user,
        password: this.config.password,
      });
    }
  }

  async query(sql: string, params?: unknown[]) {
    await this.connect();
    return this.connection!.query(sql, params);
  }

  async disconnect() {
    if (this.connection) {
      await this.connection.end();
      this.connection = null;
    }
  }
}

export class MongoDBCredential {
  private client: MongoClient | null = null;
  private dbName: string;

  constructor(private config: MongoDBConfig) {
    this.dbName = config.database;
  }

  async connect() {
    if (!this.client) {
      this.client = new MongoClient(this.config.connectionString);
      await this.client.connect();
    }
  }

  async getDb() {
    await this.connect();
    return this.client!.db(this.dbName);
  }

  async collection(name: string) {
    const db = await this.getDb();
    return db.collection(name);
  }

  async disconnect() {
    if (this.client) {
      await this.client.close();
      this.client = null;
    }
  }
}

export class RedisCredential {
  private client: ReturnType<typeof createRedisClient> | null = null;

  constructor(private config: RedisConfig) {}

  async connect() {
    if (!this.client) {
      this.client = createRedisClient({
        socket: {
          host: this.config.host,
          port: this.config.port,
        },
        password: this.config.password,
        database: this.config.database,
      });
      await this.client.connect();
    }
  }

  async get(key: string) {
    await this.connect();
    return this.client!.get(key);
  }

  async set(key: string, value: string) {
    await this.connect();
    return this.client!.set(key, value);
  }

  async disconnect() {
    if (this.client) {
      await this.client.quit();
      this.client = null;
    }
  }
}

export class OpenAICredential {
  private client: OpenAI | null = null;

  constructor(private config: OpenAIConfig) {}

  getClient(): OpenAI {
    if (!this.client) {
      this.client = new OpenAI({
        apiKey: this.config.apiKey,
        organization: this.config.organization,
        baseURL: this.config.baseUrl,
      });
    }
    return this.client;
  }

  async disconnect() {
    this.client = null;
  }
}

export class AnthropicCredential {
  private client: Anthropic | null = null;

  constructor(private config: AnthropicConfig) {}

  getClient(): Anthropic {
    if (!this.client) {
      this.client = new Anthropic({
        apiKey: this.config.apiKey,
        baseURL: this.config.baseUrl,
      });
    }
    return this.client;
  }

  async disconnect() {
    this.client = null;
  }
}

export class GoogleAICredential {
  private config: GoogleAIConfig;

  constructor(config: GoogleAIConfig) {
    this.config = config;
  }

  getApiKey(): string {
    return this.config.apiKey;
  }

  getBaseUrl(): string | undefined {
    return this.config.baseUrl;
  }

  async disconnect() {
    // No persistent client to disconnect
  }
}

export class OllamaCredential {
  private config: OllamaConfig;

  constructor(config: OllamaConfig) {
    this.config = config;
  }

  getBaseUrl(): string {
    return this.config.baseUrl || "http://localhost:11434";
  }

  async disconnect() {
    // No persistent client to disconnect
  }
}

export type CredentialClient = PostgresCredential | MySQLCredential | MongoDBCredential | RedisCredential | OpenAICredential | AnthropicCredential | GoogleAICredential | OllamaCredential;

// Main service class
export class CredentialService {
  private clientCache: Map<string, CredentialClient> = new Map();

  async getCredentials(organizationId: string): Promise<Record<string, CredentialClient>> {
    const creds = await db.query.credentials.findMany({
      where: eq(credentials.organizationId, organizationId),
    });

    const credentialClients: Record<string, CredentialClient> = {};

    for (const cred of creds) {
      const cacheKey = `${organizationId}:${cred.id}`;

      // Check cache first
      if (this.clientCache.has(cacheKey)) {
        credentialClients[cred.name] = this.clientCache.get(cacheKey)!;
        continue;
      }

      // Decrypt and create client
      try {
        const config = decryptObject<CredentialConfig>(cred.config as string);
        const client = this.createClient(cred.type, config);

        this.clientCache.set(cacheKey, client);
        credentialClients[cred.name] = client;
      } catch (error) {
        log.error({ err: error, credential: cred.name }, 'Failed to initialize credential');
      }
    }

    return credentialClients;
  }

  private createClient(type: string, config: CredentialConfig): CredentialClient {
    switch (type) {
      case 'postgres':
        return new PostgresCredential(config as PostgresConfig);
      case 'mysql':
        return new MySQLCredential(config as MySQLConfig);
      case 'mongodb':
        return new MongoDBCredential(config as MongoDBConfig);
      case 'redis':
        return new RedisCredential(config as RedisConfig);
      case 'openai':
        return new OpenAICredential(config as OpenAIConfig);
      case 'anthropic':
        return new AnthropicCredential(config as AnthropicConfig);
      case 'google':
        return new GoogleAICredential(config as GoogleAIConfig);
      case 'ollama':
        return new OllamaCredential(config as OllamaConfig);
      default:
        throw new Error(`Unknown credential type: ${type}`);
    }
  }

  async disconnectAll() {
    for (const client of this.clientCache.values()) {
      try {
        await client.disconnect();
      } catch (error) {
        log.error({ err: error }, 'Error disconnecting client');
      }
    }
    this.clientCache.clear();
  }
}

export const credentialService = new CredentialService();

